import{_ as a,o as i,c as s,a2 as n}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Publishing","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/publishing.md","filePath":"en/guide/publishing.md"}'),t={name:"en/guide/publishing.md"};function l(o,e,r,d,h,c){return i(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="publishing" tabindex="-1">Publishing <a class="header-anchor" href="#publishing" aria-label="Permalink to &quot;Publishing&quot;">​</a></h1><p>Clearance publishes three kinds of assets via <code>vendor:publish</code> tags: config, migrations, and translations. Config and migrations are handled automatically by the installer (see <a href="/clearance-docs/en/guide/installation.html">Installation</a>); this page covers publishing them manually, and publishing translations.</p><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Publishes <code>config/clearance.php</code> to your application. See the <a href="/clearance-docs/en/guide/configuration.html">Configuration reference</a> for every key, its default, and its purpose.</p><h2 id="translations" tabindex="-1">Translations <a class="header-anchor" href="#translations" aria-label="Permalink to &quot;Translations&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>This copies the 9 bundled languages (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) to <code>lang/vendor/clearance/{locale}/ui.php</code> in your app. To add a new locale or override strings in an existing one, add a locale directory there, using <code>en/ui.php</code> as the canonical key reference. All locales expose an identical key set, verified by a dedicated test on every change.</p><h2 id="overriding-the-panel-layout" tabindex="-1">Overriding the panel layout <a class="header-anchor" href="#overriding-the-panel-layout" aria-label="Permalink to &quot;Overriding the panel layout&quot;">​</a></h2><p>The <code>layout</code> config key controls the Blade layout used by full-page components:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>Leave it <code>null</code> to use your application&#39;s default Livewire layout, or set it to a specific layout view to render the panel inside a custom shell.</p><h2 id="migrations" tabindex="-1">Migrations <a class="header-anchor" href="#migrations" aria-label="Permalink to &quot;Migrations&quot;">​</a></h2><p>Clearance&#39;s migrations are published and run automatically by <code>php artisan clearance:install</code> - the installer also publishes and runs Spatie&#39;s migrations first if the <code>roles</code> table doesn&#39;t exist yet. See <a href="/clearance-docs/en/guide/installation.html">Installation</a> for the full step-by-step flow, and the <a href="/clearance-docs/en/guide/installation.html#run-the-installer">danger callout</a> about never running a plain <code>migrate</code> on a fresh setup.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/guide/configuration.html">Configuration reference</a> - every config key</li><li><a href="/clearance-docs/en/guide/installation.html">Installation</a> - the full installer flow</li><li><a href="/clearance-docs/en/guide/migration.html">Migration</a> - <code>clearance:backfill</code> for existing Spatie installs</li></ul>`,16)])])}const g=a(t,[["render",l]]);export{u as __pageData,g as default};
